#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(void) {
    int *a = malloc(5 * sizeof(int));
    int *b = calloc(5, sizeof(int));
    memset(a, 0, 5 * sizeof(int));
    int all_zero_a = 1, all_zero_b = 1;
    for (int i = 0; i < 5; i++) {
        if (a[i] != 0) all_zero_a = 0;
        if (b[i] != 0) all_zero_b = 0;
    }
    printf("malloc+memset zeros: %s\n", all_zero_a ? "yes" : "no");
    printf("calloc zeros: %s\n", all_zero_b ? "yes" : "no");
    free(a); a = NULL;
    free(b); b = NULL;
    printf("a after free: %s\n", a == NULL ? "NULL" : "dangling");
    printf("b after free: %s\n", b == NULL ? "NULL" : "dangling");
    return 0;
}

